drizzle/0005_*.sql (generated by drizzle-kit — the standard SQLite table-rebuild):
```sql
PRAGMA foreign_keys=OFF;
CREATE TABLE `__new_tasks` ( `id` text PRIMARY KEY NOT NULL, `session_id` text, /* ...other cols... */ );
INSERT INTO `__new_tasks`(...) SELECT ... FROM `tasks`;
DROP TABLE `tasks`;
ALTER TABLE `__new_tasks` RENAME TO `tasks`;
PRAGMA foreign_keys=ON;
