const DEFAULT_SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";

export interface SseServerOptions {
  /** Defaults to $SSE_PORT env var, then 3001. Pass 0 to get an OS-assigned port. */
  port?: number;
  host?: string;
}

/**
 * Attempts to start the SSE HTTP server.
 *
 * Returns the `http.Server` instance on success, or `null` if the port is
 * unavailable (or any other bind error). In the null case the stdio MCP
 * server continues unaffected.
 */
export function startSseServer(
  taskStore: TaskStore,
  options: SseServerOptions = {}
): Promise<http.Server | null> {
  const port = options.port ?? DEFAULT_SSE_PORT;
  const host = options.host ?? DEFAULT_SSE_HOST;

  return new Promise<http.Server | null>((resolve) => {
