## Fix

### Root constraint recap
The raw `sqlite` handle is not exported. We need to issue `PRAGMA foreign_keys=OFF` **outside any transaction**, on the **same connection** that `migrate()` will use, before `migrate()` opens its wrapping transaction.

---

### NEEDS

- **`db.$client`** — The Drizzle `BetterSQLite3Database` instance exposes the underlying `better-sqlite3` `Database` handle as `db.$client`. This is part of the drizzle-orm public API for better-sqlite3 (present in drizzle-orm source and docs as the escape-hatch for the raw driver). Type: `import('better-sqlite3').Database`. If this property does not exist in the installed version of drizzle-orm, the fix cannot be written without exporting the raw handle from `client.ts`.

---

### `db/migrate.ts`

```ts
import { migrate } from "drizzle-orm/better-sqlite3/migrator";
import { db } from "./client.js";

export function runMigrations(): void {
    // `migrate()` wraps execution in a better-sqlite3 transaction.
    // SQLite silently ignores `PRAGMA foreign_keys=OFF` issued inside a
    // transaction, so the PRAGMA that drizzle-kit emits inside the SQL file
    // is a documented no-op.  We must toggle the pragma on the raw connection
    // BEFORE migrate() opens its transaction, then restore it after.
    //
    // db.$client is the escape-hatch to the underlying better-sqlite3
    // Database handle exposed by drizzle-orm/better-sqlite3.
    const client = (db as { $client: import("better-sqlite3").Database }).$client;

    client.pragma("foreign_keys = OFF");
    try {
        migrate(db, { migrationsFolder: "drizzle" });
    } finally {
        client.pragma("foreign_keys = ON");
    }
}
```

---

### TEST

Uses **better-sqlite3** directly (no extra test deps beyond what the project already has) to reproduce the exact scenario: a populated DB, a table-rebuild migration, and a CASCADE child table.

```ts
// tests/migrate-cascade.test.ts
import { describe, it, before, after } from "node:test";
import assert from "node:assert/strict";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import Database from "better-sqlite3";
import { drizzle } from "drizzle-orm/better-sqlite3";
import { migrate } from "drizzle-orm/better-sqlite3/migrator";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeTempDir(): string {
    return fs.mkdtempSync(path.join(os.tmpdir(), "migrate-test-"));
}

function writeMigration(folder: string, filename: string, sql: string): void {
    fs.mkdirSync(folder, { recursive: true });
    fs.writeFileSync(path.join(folder, filename), sql, "utf8");
}

// The drizzle migrator also needs a meta/journal.json
function writeJournal(folder: string, entries: { idx: number; tag: string }[]): void {
    const metaDir = path.join(folder, "meta");
    fs.mkdirSync(metaDir, { recursive: true });
    const journal = {
        version: "5",
        dialect: "sqlite",
        entries: entries.map((e) => ({
            idx: e.idx,
            version: "5",
            when: 0,
            tag: e.tag,
            breakpoints: false,
        })),
    };
    fs.writeFileSync(
        path.join(metaDir, "_journal.json"),
        JSON.stringify(journal),
        "utf8"
    );
}

// ---------------------------------------------------------------------------
// The table-rebuild SQL that drizzle-kit generates (mirrors 0005 pattern)
// ---------------------------------------------------------------------------
const REBUILD_MIGRATION_SQL = `
PRAGMA foreign_keys=OFF;
CREATE TABLE \`__new_tasks\` (
    \`id\`         text PRIMARY KEY NOT NULL,
    \`session_id\` text
);
INSERT INTO \`__new_tasks\` (\`id\`, \`session_id\`)
    SELECT \`id\`, \`session_id\` FROM \`tasks\`;
DROP TABLE \`tasks\`;
ALTER TABLE \`__new_tasks\` RENAME TO \`tasks\`;
PRAGMA foreign_keys=ON;
`;

// ---------------------------------------------------------------------------
// Shared state
// ---------------------------------------------------------------------------
let tmpDir: string;
let migrationsFolder: string;
let dbPath: string;

describe("runMigrations — CASCADE child rows must survive table-rebuild", () => {
    before(() => {
        tmpDir = makeTempDir();
        migrationsFolder = path.join(tmpDir, "drizzle");
        dbPath = path.join(tmpDir, "test.db");

        // --- Seed the database with the PRE-migration schema ---
        const seed = new Database(dbPath);
        seed.pragma("journal_mode = WAL");
        seed.pragma("foreign_keys = ON");

        seed.exec(`
            CREATE TABLE tasks (
                id         TEXT PRIMARY KEY NOT NULL,
                session_id TEXT NOT NULL          -- will become nullable in migration
            );
            CREATE TABLE task_events (
                id      TEXT PRIMARY KEY NOT NULL,
                task_id TEXT NOT NULL
                    REFERENCES tasks(id) ON DELETE CASCADE
            );
        `);

        seed.prepare("INSERT INTO tasks VALUES (?, ?)").run("t1", "s1");
        seed.prepare("INSERT INTO tasks VALUES (?, ?)").run("t2", "s1");
        seed.prepare("INSERT INTO task_events VALUES (?, ?)").run("e1", "t1");
        seed.prepare("INSERT INTO task_events VALUES (?, ?)").run("e2", "t2");
        seed.close();

        // --- Write the migration files ---
        writeMigration(
            migrationsFolder,
            "0005_make_session_id_nullable.sql",
            REBUILD_MIGRATION_SQL
        );
        writeJournal(migrationsFolder, [
            { idx: 0, tag: "0005_make_session_id_nullable" },
        ]);
    });

    after(() => {
        fs.rmSync(tmpDir, { recursive: true, force: true });
    });

    it("BEFORE FIX — demonstrates the bug: task_events rows are wiped", () => {
        // Fresh DB copy to keep the "after fix" test independent
        const bugDbPath = path.join(tmpDir, "bug.db");
        fs.copyFileSync(dbPath, bugDbPath);

        const sqlite = new Database(bugDbPath);
        sqlite.pragma("journal_mode = WAL");
        sqlite.pragma("foreign_keys = ON");
        const bugDb = drizzle(sqlite);

        // Run migrate WITHOUT the pragma guard — this is the buggy behaviour
        migrate(bugDb, { migrationsFolder });
        sqlite.close();

        // Verify: task_events should be empty (the bug)
        const check = new Database(bugDbPath);
        const rows = check.prepare("SELECT COUNT(*) AS n FROM task_events").get() as { n: number };
        check.close();

        assert.equal(
            rows.n,
            0,
            "Bug confirmation: task_events was wiped by the unguarded migrate()"
        );
    });

    it("AFTER FIX — task_events rows survive the table-rebuild migration", () => {
        const fixDbPath = path.join(tmpDir, "fix.db");
        fs.copyFileSync(dbPath, fixDbPath);

        const sqlite = new Database(fixDbPath);
        sqlite.pragma("journal_mode = WAL");
        sqlite.pragma("foreign_keys = ON");
        const fixDb = drizzle(sqlite);

        // ---------------------------------------------------------------
        // THE FIX: toggle foreign_keys around migrate() via db.$client
        // ---------------------------------------------------------------
        const client = (fixDb as unknown as { $client: Database.Database }).$client;

        client.pragma("foreign_keys = OFF");
        try {
            migrate(fixDb, { migrationsFolder });
        } finally {
            client.pragma("foreign_keys = ON");
        }
        sqlite.close();

        // Verify: both task_events rows must still exist
        const check = new Database(fixDbPath);
        const rows = check
            .prepare("SELECT COUNT(*) AS n FROM task_events")
            .get() as { n: number };
        check.close();

        assert.equal(
            rows.n,
            2,
            "Fix: task_events rows must survive the table-rebuild migration"
        );
    });

    it("AFTER FIX — foreign_keys is restored to ON after runMigrations", () => {
        const fixDbPath = path.join(tmpDir, "fix_fk_restore.db");
        fs.copyFileSync(dbPath, fixDbPath);

        const sqlite = new Database(fixDbPath);
        sqlite.pragma("journal_mode = WAL");
        sqlite.pragma("foreign_keys = ON");
        const fixDb = drizzle(sqlite);

        const client = (fixDb as unknown as { $client: Database.Database }).$client;

        client.pragma("foreign_keys = OFF");
        try {
            migrate(fixDb, { migrationsFolder });
        } finally {
            client.pragma("foreign_keys = ON");
        }

        // foreign_keys pragma returns an array of objects: [{ foreign_keys: 0|1 }]
        const [{ foreign_keys }] = sqlite.pragma("foreign_keys") as [{ foreign_keys: number }];
        sqlite.close();

        assert.equal(foreign_keys, 1, "foreign_keys must be restored to ON after migration");
    });
});
```

---

### Why the fix is at the correct layer

| Layer | Why wrong to fix there |
|---|---|
| `drizzle/0005_*.sql` | Already has the PRAGMA; SQLite ignores it inside a transaction — can't be fixed in SQL |
| `db/schema.ts` | Weakening `ON DELETE CASCADE` breaks an intentional invariant |
| `db/client.ts` | `foreign_keys = ON` at open time is correct for runtime; migration startup is a different lifecycle phase |
| **`db/migrate.ts`** ✓ | Only place that controls the lifecycle bracket around `migrate()` |

---

### CONFIDENCE

**Medium-high.**

Most likely way I am wrong: **`db.$client` may not exist under that exact name in the version of drizzle-orm installed.** The drizzle-orm better-sqlite3 adapter does expose the underlying driver handle, but the property name (`$client` vs `session.client` vs something else) has varied across versions. If `db.$client` is undefined at runtime, `client.pragma(...)` will throw a `TypeError` rather than silently failing, which makes the failure obvious and the fix straightforward — export the raw `sqlite` handle from `client.ts` and import it directly in `migrate.ts`.

