import os from "node:os";
import fs from "node:fs";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeTempDb() {
    const dir = fs.mkdtempSync(path.join(os.tmpdir(), "mig-test-"));
    const dbPath = path.join(dir, "test.db");
    return { dir, dbPath };
}

/**
 * Writes a minimal two-file migration folder:
 *   0001 – creates `tasks` (session_id NOT NULL) + `task_events` with CASCADE
 *   0002 – rebuilds `tasks` making session_id nullable  (the bug trigger)
 */
function writeMigrations(migrationsDir: string) {
    fs.mkdirSync(migrationsDir, { recursive: true });

    // journal file drizzle-kit expects
    const journal = {
        version: "5",
        dialect: "sqlite",
        entries: [
            { idx: 0, version: "5", when: 1, tag: "0001_init", breakpoints: false },
            { idx: 1, version: "5", when: 2, tag: "0002_nullable_session", breakpoints: false },
        ],
    };
    fs.writeFileSync(
        path.join(migrationsDir, "meta", "_journal.json"),
        JSON.stringify(journal),
        "utf8",
    );
    fs.mkdirSync(path.join(migrationsDir, "meta"), { recursive: true });

    // 0001: initial schema — session_id NOT NULL
    fs.writeFileSync(
        path.join(migrationsDir, "0001_init.sql"),
        `
CREATE TABLE tasks (
  id   TEXT PRIMARY KEY,
  session_id TEXT NOT NULL
);
CREATE TABLE task_events (
  id      TEXT PRIMARY KEY,
  task_id TEXT NOT NULL REFERENCES tasks(id) ON DELETE CASCADE
);
`.trim(),
    );

    // 0002: make session_id nullable — drizzle-kit table-rebuild pattern
    fs.writeFileSync(
        path.join(migrationsDir, "0002_nullable_session.sql"),
        `
PRAGMA foreign_keys=OFF;
CREATE TABLE \`__new_tasks\` (
  \`id\`         text PRIMARY KEY NOT NULL,
  \`session_id\` text
);
INSERT INTO \`__new_tasks\`(\`id\`, \`session_id\`) SELECT \`id\`, \`session_id\` FROM \`tasks\`;
DROP TABLE \`tasks\`;
ALTER TABLE \`__new_tasks\` RENAME TO \`tasks\`;
PRAGMA foreign_keys=ON;
`.trim(),
    );
}

// ---------------------------------------------------------------------------
// The helper under test (inline copy so the test is self-contained and does
// NOT depend on the module-private `sqlite` handle from the real client.ts)
// ---------------------------------------------------------------------------

function withForeignKeysDisabled(sqlite: Database.Database, fn: () => void): void {
    const [{ foreign_keys: prior }] = sqlite
        .pragma("foreign_keys") as [{ foreign_keys: number }];
    sqlite.pragma("foreign_keys = OFF");
    try {
        fn();
    } finally {
        sqlite.pragma(`foreign_keys = ${prior === 1 ? "ON" : "OFF"}`);
    }
}

