    );

    // Give event loop time to process error
    return new Promise<void>((resolve) => {
      setTimeout(() => {
        server.close();
        resolve();
      }, 10);
    });
  });

  it("should allow configurable port", () => {
    const server = startSseServer(
      {} as any,
      { port: 3002, host: "127.0.0.1" }
    );

    expect(server.address()).toEqual({ 
      port: 3002, 
      host: "127.0.0.1",
      family: "IPv4"
    });

    server.close();
  });
