        const conflictingServer = http.createServer();
        const testPort = 3001;
        const serverPromise = new Promise((resolve) => {
            conflictingServer.listen(testPort, "127.0.0.1", () => {
                resolve(undefined);
            });
        });

        await serverPromise;

        // Try to start the SSE server - should not crash process
        const sseServer = startSseServer({} as any);

        // Give it time to attempt binding
        await new Promise((resolve) => setTimeout(resolve, 100));

        // The process should not have crashed - we can still execute code here
        assert.ok(sseServer);

        // Clean up the conflicting server
        await new Promise((resolve) => {
            conflictingServer.close(() => resolve(undefined));
        });
    });

    it("should allow custom port configuration", () => {
        process.env.SSE_PORT = "3002";

        // This should not crash the process even if port is in use
        const sseServer = startSseServer({} as any);

        // Should still return a server instance
        assert.ok(sseServer);
    });
});
