BEGIN TRANSACTION;

-- 1. Create the new table with the relaxed constraint
CREATE TABLE `tasks_new` (
  `id`          INTEGER PRIMARY KEY AUTOINCREMENT,
  `title`       TEXT    NOT NULL,
  `description` TEXT,            -- <-- now nullable (was NOT NULL)
  -- ... all other columns verbatim ...
  FOREIGN KEY (`user_id`) REFERENCES `users`(`id`)
);

-- 2. Copy ALL existing data
INSERT INTO `tasks_new` SELECT * FROM `tasks`;

-- 3. Drop the OLD table (FK enforcement is OFF, so task_events is untouched)
DROP TABLE `tasks`;

-- 4. Rename
ALTER TABLE `tasks_new` RENAME TO `tasks`;

-- 5. Recreate any indexes that existed on tasks
-- CREATE INDEX ...

COMMIT;

PRAGMA foreign_keys = ON;    -- re-enable AFTER commit
