## Fix

### Root constraint recap
`sqlite` (the raw `Database` handle) is module-private. We cannot reach it from outside `client.ts`. The fix must therefore live **inside `client.ts`** — we export a helper that runs a caller-supplied function with `foreign_keys` toggled off *outside* any transaction.

---

### db/client.ts — add and export `withForeignKeysOff`

```ts
// db/client.ts
import Database from "better-sqlite3";
import { drizzle } from "drizzle-orm/better-sqlite3";
import * as schema from "./schema.js";

const sqlite = new Database(resolvedPath);          // module-private; unchanged
sqlite.pragma("journal_mode = WAL");
sqlite.pragma("foreign_keys = ON");

export const db = drizzle(sqlite, { schema });      // unchanged

/**
 * Runs `fn` with SQLite foreign-key enforcement disabled on the underlying
 * connection, then unconditionally restores it.
 *
 * MUST be called outside any open transaction — SQLite silently ignores
 * PRAGMA foreign_keys inside a transaction.
 */
export function withForeignKeysOff<T>(fn: () => T): T {
    // Verify we are not already inside a transaction.
    // better-sqlite3 exposes `sqlite.inTransaction` (boolean, readonly).
    if (sqlite.inTransaction) {
        throw new Error(
            "withForeignKeysOff() must be called outside an active transaction. " +
            "PRAGMA foreign_keys is a no-op inside a transaction (SQLite docs)."
        );
    }
    sqlite.pragma("foreign_keys = OFF");
    try {
        return fn();
    } finally {
        sqlite.pragma("foreign_keys = ON");
    }
}
```

---

### db/migrate.ts — wrap `migrate()` with the helper

```ts
// db/migrate.ts
import { migrate } from "drizzle-orm/better-sqlite3/migrator";
import { db, withForeignKeysOff } from "./client.js";

export function runMigrations(): void {
    // migrate() wraps execution in a better-sqlite3 transaction internally,
    // which makes any PRAGMA foreign_keys inside the SQL a silent no-op.
    // We disable foreign keys HERE, on the raw connection, before that
    // transaction is opened, so the DROP TABLE in 0005 does not cascade.
    withForeignKeysOff(() => {
        migrate(db, { migrationsFolder: "...drizzle" });
    });
}
```

