### TEST

Uses only `better-sqlite3` + `drizzle-orm` APIs visible in the provided context. No test framework assumed beyond a simple assertion helper — swap `assert` for your project's runner trivially.

```ts
// db/migrate.test.ts
import assert from "node:assert/strict";
import { after, before, describe, it } from "node:test";   // node:test (Node 18+)
import Database from "better-sqlite3";
import { drizzle } from "drizzle-orm/better-sqlite3";
import { migrate } from "drizzle-orm/better-sqlite3/migrator";
import path from "node:path";
import os from "node:os";
import fs from "node:fs";

// ---------------------------------------------------------------------------
// Helpers — build a minimal in-process DB that mirrors the real schema up to
// migration 0004 (tasks.session_id NOT NULL), then run 0005 via runMigrations.
// ---------------------------------------------------------------------------

function makeTempDir(): string {
    return fs.mkdtempSync(path.join(os.tmpdir(), "migrate-test-"));
}

function buildPreMigrationDb(dbPath: string): Database.Database {
    const sqlite = new Database(dbPath);
    sqlite.pragma("journal_mode = WAL");
    sqlite.pragma("foreign_keys = ON");

    // Schema as it exists BEFORE migration 0005
    sqlite.exec(`
        CREATE TABLE tasks (
            id   TEXT PRIMARY KEY NOT NULL,
            session_id TEXT NOT NULL          -- NOT NULL: pre-0005 state
        );

        CREATE TABLE task_events (
            id      TEXT PRIMARY KEY NOT NULL,
            task_id TEXT NOT NULL
                REFERENCES tasks(id) ON DELETE CASCADE
        );
    `);

    // Seed data
    sqlite.exec(`
        INSERT INTO tasks       VALUES ('task-1', 'sess-abc');
        INSERT INTO task_events VALUES ('evt-1',  'task-1');
        INSERT INTO task_events VALUES ('evt-2',  'task-1');
    `);

    return sqlite;
}

// ---------------------------------------------------------------------------
// The migration SQL that drizzle-kit would generate for 0005
// (makes session_id nullable — standard SQLite table-rebuild).
// We write it to a temp migrations folder so the real migrator can pick it up.
// ---------------------------------------------------------------------------

const MIGRATION_0005_SQL = `
PRAGMA foreign_keys=OFF;
CREATE TABLE \`__new_tasks\` (
    \`id\`         text PRIMARY KEY NOT NULL,
    \`session_id\` text             -- nullable: the change introduced by 0005
);
INSERT INTO \`__new_tasks\` (\`id\`, \`session_id\`)
    SELECT \`id\`, \`session_id\` FROM \`tasks\`;
DROP TABLE \`tasks\`;
ALTER TABLE \`__new_tasks\` RENAME TO \`tasks\`;
PRAGMA foreign_keys=ON;
`.trim();

function writeMigrationsFolder(dir: string): string {
    const migrationsDir = path.join(dir, "drizzle");
    fs.mkdirSync(migrationsDir);

    // drizzle-orm migrator expects a meta/journal.json + numbered .sql files
    const journal = {
        version: "5",
        dialect: "sqlite",
        entries: [
            {
                idx: 5,
                version: "5",
                when: 0,
                tag: "0005_make_session_id_nullable",
                breakpoints: false,
            },
        ],
    };
    fs.mkdirSync(path.join(migrationsDir, "meta"));
    fs.writeFileSync(
        path.join(migrationsDir, "meta", "journal.json"),
        JSON.stringify(journal)
    );
    fs.writeFileSync(
        path.join(migrationsDir, "0005_make_session_id_nullable.sql"),
        MIGRATION_0005_SQL
    );

    return migrationsDir;
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("runMigrations — migration 0005 must not wipe task_events", () => {
    let tmpDir: string;

    before(() => { tmpDir = makeTempDir(); });
    after(() => { fs.rmSync(tmpDir, { recursive: true, force: true }); });

    it("FAILS (demonstrates the bug) when foreign_keys is ON inside the migrator transaction", () => {
        const dbPath = path.join(tmpDir, "bug.db");
        const sqlite = buildPreMigrationDb(dbPath);
        const db = drizzle(sqlite, {});
        const migrationsFolder = writeMigrationsFolder(path.join(tmpDir, "bug"));

        // Naive call — no withForeignKeysOff wrapper
        migrate(db, { migrationsFolder });

        const rows = sqlite
            .prepare("SELECT id FROM task_events")
            .all() as { id: string }[];

        // This assertion FAILS before the fix: rows.length === 0
        assert.equal(
            rows.length,
            2,
            `BUG REPRODUCED: expected 2 task_events rows, got ${rows.length}`
        );
    });

    it("PASSES (fix) when foreign_keys is toggled off outside the migrator transaction", () => {
        const dbPath = path.join(tmpDir, "fix.db");
        const sqlite = buildPreMigrationDb(dbPath);
        const db = drizzle(sqlite, {});
        const migrationsFolder = writeMigrationsFolder(path.join(tmpDir, "fix"));

        // ---- THE FIX: disable FK enforcement before migrate() opens its tx --
        assert.equal(
            (sqlite as any).inTransaction,   // better-sqlite3 Database.inTransaction
            false,
            "must not already be in a transaction before toggling pragma"
        );

        sqlite.pragma("foreign_keys = OFF");
        try {
            migrate(db, { migrationsFolder });
        } finally {
            sqlite.pragma("foreign_keys = ON");
        }
        // ---- end fix -------------------------------------------------------

        const rows = sqlite
            .prepare("SELECT id FROM task_events")
            .all() as { id: string }[];

        assert.equal(rows.length, 2, `expected 2 task_events rows, got ${rows.length}`);

        // Also verify the schema change landed: session_id is now nullable
        sqlite.prepare("UPDATE tasks SET session_id = NULL WHERE id = 'task-1'").run();
        const task = sqlite
            .prepare("SELECT session_id FROM tasks WHERE id = 'task-1'")
            .get() as { session_id: string | null };
        assert.equal(task.session_id, null, "session_id should be nullable after 0005");
    });

    it("withForeignKeysOff throws if called inside an open transaction", () => {
        // Inline the guard logic (mirrors what client.ts exports)
        const sqlite = new Database(":memory:");
        sqlite.pragma("foreign_keys = ON");

        const withForeignKeysOff = <T>(fn: () => T): T => {
            if ((sqlite as any).inTransaction) {
                throw new Error("must be called outside an active transaction");
            }
            sqlite.pragma("foreign_keys = OFF");
            try { return fn(); }
            finally { sqlite.pragma("foreign_keys = ON"); }
        };

        const tx = sqlite.transaction(() => {
            assert.throws(
                () => withForeignKeysOff(() => {}),
                /must be called outside an active transaction/
            );
        });
        tx();   // run the transaction so the inner assertion fires
    });
});
```

---

### Why this is the correct layer

| Layer | Why wrong to fix here |
|---|---|
| Migration SQL (`0005_*.sql`) | Already correct; pragma is present. Problem is the execution context, not the SQL. |
| `drizzle-orm` migrator internals | We don't own that code; patching it would break on upgrades. |
| **`client.ts` + `migrate.ts`** ✓ | We own both; toggling the pragma on the raw connection *before* the migrator opens its transaction is exactly what SQLite requires. |

---

### NEEDS

- **`Database.inTransaction`** (boolean, readonly) — documented `better-sqlite3` property on a `Database` instance; used in the guard inside `withForeignKeysOff`. Confirmed present in better-sqlite3 public API docs. Not present in the provided context snippets, so stated explicitly here.

---

